// MGA principal view of ALL insurance-vertical leads. Filter at the
// query layer by industry='insurance' (covers all insurance B2C +
// marketplace + applications since they're all tagged industry=insurance
// by the source workflows). Single equality filter — simplest, no
// PostgREST OR-syntax issues.
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const f = (body.filters || {});
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 100, 1), 500);
let qs = 'select=id,full_name,email,phone,company,job_title,industry,city,lead_status,lead_score,source,client_id,lead_type,product_type,notes,date_created,updated_at';
qs += '&industry=eq.insurance&order=date_created.desc&limit=' + limit;
if (f.status && f.status !== 'all') qs += '&lead_status=eq.' + encodeURIComponent(f.status);
if (f.source && f.source !== 'all') qs += '&source=eq.' + encodeURIComponent(f.source);
if (f.lead_id) qs = 'select=id,full_name,email,phone,company,job_title,industry,city,lead_status,lead_score,source,client_id,lead_type,product_type,notes,date_created,updated_at&id=eq.' + encodeURIComponent(f.lead_id) + '&limit=1';
return { json: { token, qs } };

// Allow mga_principal, compliance_officer, supervisor, admin.
// MGA principals view ALL insurance leads (not just their own assignments).
const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
const allowedRoles = ['mga_principal','compliance_officer','supervisor','admin'];
if (allowedRoles.indexOf(row.user_role) === -1) return { json: { ok: false, status: 403, error: 'MGA principal access required' } };
return { json: { ok: true, qs: $('Extract Inputs').item.json.qs } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const leads = allOf('Query Leads');
// Bucket counts so the principal dashboard can show 'X advisor apps, Y carrier inquiries, Z B2C consumers'.
const counts = { total: leads.length, advisor_applications: 0, carrier_inquiries: 0, marketplace: 0, marketing_site: 0, other: 0 };
leads.forEach(function (l) {
  if (l.source === 'advisor_application') counts.advisor_applications++;
  else if (l.source === 'carrier_inquiry') counts.carrier_inquiries++;
  else if (l.source && l.source.indexOf('marketplace_') === 0) counts.marketplace++;
  else if (l.source === 'marketing_site') counts.marketing_site++;
  else counts.other++;
});
return { json: { ok: true, leads: leads, counts: counts } };
